const __pageData = JSON.parse('{"title":"SSR性能：从首字节到可交互","description":"深入解析服务端渲染（SSR）的性能模型、流式渲染时序理论、部分水合架构与边缘渲染延迟模型，涵盖 Next.js、Nuxt、Astro、Remix 及 React Server Components 的工程实践与内存泄漏排查。","frontmatter":{"title":"SSR性能：从首字节到可交互","description":"深入解析服务端渲染（SSR）的性能模型、流式渲染时序理论、部分水合架构与边缘渲染延迟模型，涵盖 Next.js、Nuxt、Astro、Remix 及 React Server Components 的工程实践与内存泄漏排查。","date":"2026-05-01T00:00:00.000Z","tags":["性能工程","SSR","服务端渲染","流式渲染","边缘计算","Next.js","Nuxt","Astro","Remix","React Server Components"],"category":"engineering"},"headers":[],"relativePath":"performance-engineering/09-ssr-performance.md","filePath":"performance-engineering/09-ssr-performance.md","lastUpdated":1777741461000}');
